import React from "react";
import { useNavigate } from "react-router-dom";
import { authService } from "../services";
import "../styles/Dashboard.css";

const UserDashboard = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();

  const handleLogout = () => {
    authService.logout();
    navigate("/user/login");
  };

  return (
    <div className="dashboard-container">
      <div className="dashboard-header user-header">
        <h1>User Dashboard</h1>
        <p className="subtitle">Welcome, {user?.name}!</p>
        <div className="header-actions">
          <button
            onClick={() => navigate("/create-load")}
            className="btn-primary"
          >
            Create New Load
          </button>
          <button onClick={handleLogout} className="btn-secondary">
            Logout
          </button>
        </div>
      </div>

      <div className="dashboard-content">
        <div className="info-card user-info">
          <h3>Load Management System</h3>
          <p>Manage your loads efficiently with our platform.</p>
          <ul>
            <li>Create and manage loads</li>
            <li>Track load status</li>
            <li>View all available loads</li>
            <li>Edit or delete your loads</li>
          </ul>
          <button onClick={() => navigate("/loads")} className="btn-primary">
            Go to Loads
          </button>
        </div>

        <div className="quick-stats">
          <div className="stat-card">
            <h4>Email</h4>
            <p>{user?.email}</p>
          </div>
          <div className="stat-card">
            <h4>Role</h4>
            <p className="role-badge user-badge">{user?.role?.toUpperCase()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserDashboard;
